# ========== Figure 1: Phillips Curve ==========
fig, ax = plt.subplots(figsize=(12, 9))

# Real US
ax.scatter(real_unemp_phillips, real_wage_phillips, c=REAL_COLOR, alpha=0.85, s=90, marker='D', label='Real US', zorder=3)

# 7B base pooled
for unemp, wage in zip(all_7b_unemp_phillips, all_7b_wage):
    ax.scatter(unemp, wage, c=BASE7B_COLOR, alpha=0.4, s=50, marker='s', zorder=2)
ax.scatter([], [], c=BASE7B_COLOR, s=50, marker='s', label='QWEN2.5-7B Base (5 runs)')

# Qwen3-4B pooled
for unemp, wage in zip(all_4b_unemp_phillips, all_4b_wage):
    ax.scatter(unemp, wage, c=QWEN3_4B_COLOR, alpha=0.4, s=50, marker='v', zorder=2)
ax.scatter([], [], c=QWEN3_4B_COLOR, s=50, marker='v', label='Qwen3-4B-Instruct (5 runs)')

# IW pooled
for unemp, wage in zip(all_iw_unemp_phillips, all_iw_wage):
    ax.scatter(unemp, wage, c=IW_COLOR, alpha=0.4, s=50, marker='^', zorder=2)
ax.scatter([], [], c=IW_COLOR, s=50, marker='^', label='7B Fewshot IW (5 runs)')

# BR pooled
for unemp, wage in zip(all_br_unemp_phillips, all_br_wage):
    ax.scatter(unemp, wage, c=BR_COLOR, alpha=0.4, s=50, marker='P', zorder=2)
ax.scatter([], [], c=BR_COLOR, s=50, marker='P', label='7B Fewshot BR (5 runs)')

# BR4B pooled
for unemp, wage in zip(all_br4b_unemp_phillips, all_br4b_wage):
    ax.scatter(unemp, wage, c=BR4B_COLOR, alpha=0.4, s=50, marker='X', zorder=2)
ax.scatter([], [], c=BR4B_COLOR, s=50, marker='X', label='4B Fewshot BR (5 runs)')

# Regression: Real US
slope_r, intercept_r, r_r, p_r, _ = stats.linregress(real_unemp_phillips, real_wage_phillips)

# Regression: 7B per-run then mean
fits_7b = [stats.linregress(u, w) for u, w in zip(all_7b_unemp_phillips, all_7b_wage)]
slope_7b = np.mean([f.slope for f in fits_7b])
intercept_7b = np.mean([f.intercept for f in fits_7b])
r_7b = np.mean([f.rvalue for f in fits_7b])
p_7b = np.mean([f.pvalue for f in fits_7b])

# Regression: 4B per-run then mean
fits_4b = [stats.linregress(u, w) for u, w in zip(all_4b_unemp_phillips, all_4b_wage)]
slope_4b = np.mean([f.slope for f in fits_4b])
intercept_4b = np.mean([f.intercept for f in fits_4b])
r_4b = np.mean([f.rvalue for f in fits_4b])
p_4b = np.mean([f.pvalue for f in fits_4b])

# Regression: IW per-run then mean
fits_iw = [stats.linregress(u, w) for u, w in zip(all_iw_unemp_phillips, all_iw_wage)]
slope_iw = np.mean([f.slope for f in fits_iw])
intercept_iw = np.mean([f.intercept for f in fits_iw])
r_iw = np.mean([f.rvalue for f in fits_iw])
p_iw = np.mean([f.pvalue for f in fits_iw])

# Regression: BR per-run then mean
fits_br = [stats.linregress(u, w) for u, w in zip(all_br_unemp_phillips, all_br_wage)]
slope_br = np.mean([f.slope for f in fits_br])
intercept_br = np.mean([f.intercept for f in fits_br])
r_br = np.mean([f.rvalue for f in fits_br])
p_br = np.mean([f.pvalue for f in fits_br])

# Regression: BR4B per-run then mean
fits_br4b = [stats.linregress(u, w) for u, w in zip(all_br4b_unemp_phillips, all_br4b_wage)]
slope_br4b = np.mean([f.slope for f in fits_br4b])
intercept_br4b = np.mean([f.intercept for f in fits_br4b])
r_br4b = np.mean([f.rvalue for f in fits_br4b])
p_br4b = np.mean([f.pvalue for f in fits_br4b])

all_x = real_unemp_phillips + sum(all_7b_unemp_phillips, []) + sum(all_4b_unemp_phillips, []) + sum(all_iw_unemp_phillips, []) + sum(all_br_unemp_phillips, []) + sum(all_br4b_unemp_phillips, [])
x_line = np.linspace(min(all_x) - 0.5, max(all_x) + 0.5, 200)

ax.plot(x_line, slope_r * x_line + intercept_r, color=REAL_COLOR, linestyle='--', linewidth=2, alpha=0.8,
        label=f'Real US fit (R\u00b2={r_r**2:.3f})')
ax.plot(x_line, slope_7b * x_line + intercept_7b, color=BASE7B_COLOR, linestyle='--', linewidth=2, alpha=0.8,
        label=f'7B Base fit (mean R\u00b2={r_7b**2:.3f})')
ax.plot(x_line, slope_4b * x_line + intercept_4b, color=QWEN3_4B_COLOR, linestyle='--', linewidth=2, alpha=0.8,
        label=f'Qwen3-4B fit (mean R\u00b2={r_4b**2:.3f})')
ax.plot(x_line, slope_iw * x_line + intercept_iw, color=IW_COLOR, linestyle='--', linewidth=2, alpha=0.8,
        label=f'7B IW fit (mean R\u00b2={r_iw**2:.3f})')
ax.plot(x_line, slope_br * x_line + intercept_br, color=BR_COLOR, linestyle='--', linewidth=2, alpha=0.8,
        label=f'7B BR fit (mean R\u00b2={r_br**2:.3f})')
ax.plot(x_line, slope_br4b * x_line + intercept_br4b, color=BR4B_COLOR, linestyle='--', linewidth=2, alpha=0.8,
        label=f'4B BR fit (mean R\u00b2={r_br4b**2:.3f})')

ax.set_xlabel('Unemployment Rate (%)', fontsize=14)
ax.set_ylabel('Wage Inflation (%)', fontsize=14)
ax.set_title('Phillips Curve Comparison', fontsize=16)
ax.legend(fontsize=11, loc='best')
ax.grid(True, alpha=0.3)
plt.tight_layout()
plt.savefig(os.path.join(BASE_PATH, 'phillips_curve_comparison.png'), dpi=300, bbox_inches='tight')
plt.close()

